import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import SEO from './SEO'
import { authAPI } from '../services/api'

const Register = ({ theme, toggleTheme }) => {
    const [formData, setFormData] = useState({ name: '', email: '', password: '', confirm: '' })
    const [showPassword, setShowPassword] = useState(false)
    const [showConfirm, setShowConfirm] = useState(false)
    const [loading, setLoading] = useState(false)
    const [errors, setErrors] = useState({})
    const navigate = useNavigate()

    const validate = () => {
        const e = {}
        if (!formData.name.trim()) e.name = 'Full name is required'
        if (!formData.email) e.email = 'Email is required'
        else if (!/\S+@\S+\.\S+/.test(formData.email)) e.email = 'Enter a valid email'
        if (!formData.password) e.password = 'Password is required'
        else if (formData.password.length < 6) e.password = 'Minimum 6 characters'
        if (!formData.confirm) e.confirm = 'Please confirm your password'
        else if (formData.confirm !== formData.password) e.confirm = 'Passwords do not match'
        return e
    }

    const handleChange = (e) => {
        const { name, value } = e.target
        setFormData(prev => ({ ...prev, [name]: value }))
        if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }))
    }

    const handleSubmit = async (e) => {
        e.preventDefault()
        const validationErrors = validate()
        if (Object.keys(validationErrors).length > 0) { setErrors(validationErrors); return }
        setLoading(true)

        try {
            await authAPI.register({
                name: formData.name,
                email: formData.email,
                password: formData.password,
                role: 'Client'
            })
            navigate('/login')
        } catch (error) {
            setErrors({ email: error.message || 'Registration failed. Please try again.' })
        } finally {
            setLoading(false)
        }
    }

    const EyeOpen = () => <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><circle cx="12" cy="12" r="3" stroke="currentColor" strokeWidth="2" /></svg>
    const EyeOff = () => <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><line x1="1" y1="1" x2="23" y2="23" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>

    return (
        <>
            <SEO title="Create Account | CodeNexus Studio" description="Sign up for a free CodeNexus Studio account and start building high-performance web apps today." canonical="https://codenexusstudio.vercel.app/register" />

            <div className="min-h-screen flex flex-col bg-[var(--bg-dark)] relative overflow-hidden">
                <div className="absolute rounded-full z-0 animate-[blobFloat_12s_infinite_alternate] pointer-events-none w-[520px] h-[520px] -top-[15%] -right-[10%] bg-[radial-gradient(circle,rgba(168,85,247,0.35),transparent_70%)]"></div>
                <div className="absolute rounded-full z-0 animate-[blobFloat_12s_infinite_alternate] pointer-events-none w-[480px] h-[480px] -bottom-[12%] -left-[10%] bg-[radial-gradient(circle,var(--primary-glow),transparent_70%)] [animation-delay:-6s]"></div>

                <header className="flex items-center justify-between py-5 px-10 max-sm:px-5 relative z-10">
                    <Link to="/" className="font-['Outfit'] text-2xl font-extrabold text-[var(--text-main)] no-underline tracking-[-0.5px] transition-opacity duration-300 hover:opacity-80">Code<span className="bg-gradient-to-br from-[var(--primary)] to-[var(--accent)] bg-clip-text [-webkit-text-fill-color:transparent]">Nexus</span>.</Link>
                    <button className="bg-[rgba(255,255,255,0.05)] border border-[var(--glass-border)] rounded-full w-10 h-10 text-[1.1rem] cursor-pointer transition-all duration-300 flex items-center justify-center color-[var(--text-main)] hover:scale-105 hover:bg-[rgba(255,255,255,0.1)] hover:border-[var(--accent)]" onClick={toggleTheme} aria-label="Toggle theme">
                        {theme === 'light' ? '🌞' : '🌙'}
                    </button>
                </header>

                <main className="flex-1 flex items-center justify-center py-8 px-4 relative z-[5]">
                    <div className="bg-[var(--glass-bg)] border border-[var(--glass-border)] backdrop-blur-[20px] rounded-3xl p-10 py-10 px-9 max-sm:p-7 w-full max-w-[460px] shadow-[0_8px_32px_rgba(0,0,0,0.35),inset_0_0_0_1px_var(--glass-border)] animate-[cardFadeIn_0.6s_cubic-bezier(0.22,1,0.36,1)]">
                        <div className="w-[58px] h-[58px] rounded-2xl bg-gradient-to-br from-[var(--accent)] to-[var(--primary)] flex items-center justify-center mx-auto mb-[1.4rem] shadow-[0_8px_24px_rgba(168,85,247,0.35)]">
                            <svg viewBox="0 0 24 24" fill="none" className="w-[26px] h-[26px] text-white">
                                <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
                                <circle cx="9" cy="7" r="4" stroke="currentColor" strokeWidth="2" />
                                <line x1="19" y1="8" x2="19" y2="14" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
                                <line x1="22" y1="11" x2="16" y2="11" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
                            </svg>
                        </div>

                        <h1 className="text-[1.8rem] max-sm:text-[1.55rem] font-extrabold text-center text-[var(--text-main)] mb-1.5 tracking-[-0.5px]">Create Account</h1>
                        <p className="text-center text-[var(--text-muted)] text-[0.93rem] mb-7">Join CodeNexus — it's free forever</p>

                        <form onSubmit={handleSubmit} className="flex flex-col gap-[1.1rem]" noValidate>
                            {[
                                { id: 'reg-name', name: 'name', type: 'text', label: 'Full Name', placeholder: 'Your full name', autoComplete: 'name', icon: <><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /><circle cx="12" cy="7" r="4" stroke="currentColor" strokeWidth="2" /></> },
                                { id: 'reg-email', name: 'email', type: 'email', label: 'Email Address', placeholder: 'you@example.com', autoComplete: 'email', icon: <><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /><polyline points="22,6 12,13 2,6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></> }
                            ].map(f => (
                                <div key={f.name} className="flex flex-col gap-2 focus-within:[&>label]:text-[var(--primary)]">
                                    <label htmlFor={f.id} className="text-[0.875rem] font-semibold text-[var(--text-muted)] pl-0.5 transition-colors duration-300">{f.label}</label>
                                    <div className="relative flex items-center">
                                        <span className="absolute left-[13px] flex items-center text-[var(--text-muted)] pointer-events-none">
                                            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none">{f.icon}</svg>
                                        </span>
                                        <input id={f.id} name={f.name} type={f.type} placeholder={f.placeholder} value={formData[f.name]} onChange={handleChange} autoComplete={f.autoComplete} className={`w-full py-[0.72rem] pr-4 pl-[2.6rem] bg-[rgba(255,255,255,0.05)] border-[1.5px] ${errors[f.name] ? 'border-red-400 bg-[rgba(248,113,113,0.05)]' : 'border-[var(--glass-border)] focus:border-[var(--primary)] focus:bg-[rgba(99,102,241,0.05)] focus:shadow-[0_0_0_3px_var(--primary-glow)]'} rounded-xl text-[var(--text-main)] text-[0.93rem] font-['Outfit'] outline-none transition-all duration-300 placeholder:text-[var(--text-muted)] placeholder:opacity-70`} />
                                    </div>
                                    {errors[f.name] && <span className="text-[0.8rem] text-red-400 pl-0.5">{errors[f.name]}</span>}
                                </div>
                            ))}

                            <div className="flex flex-col gap-2 focus-within:[&>label]:text-[var(--primary)]">
                                <label htmlFor="reg-password" className="text-[0.875rem] font-semibold text-[var(--text-muted)] pl-0.5 transition-colors duration-300">Password</label>
                                <div className="relative flex items-center">
                                    <span className="absolute left-[13px] flex items-center text-[var(--text-muted)] pointer-events-none">
                                        <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none"><rect x="3" y="11" width="18" height="11" rx="2" ry="2" stroke="currentColor" strokeWidth="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>
                                    </span>
                                    <input id="reg-password" name="password" type={showPassword ? 'text' : 'password'} placeholder="Min. 6 characters" value={formData.password} onChange={handleChange} autoComplete="new-password" className={`w-full py-[0.72rem] pr-4 pl-[2.6rem] bg-[rgba(255,255,255,0.05)] border-[1.5px] ${errors.password ? 'border-red-400 bg-[rgba(248,113,113,0.05)]' : 'border-[var(--glass-border)] focus:border-[var(--primary)] focus:bg-[rgba(99,102,241,0.05)] focus:shadow-[0_0_0_3px_var(--primary-glow)]'} rounded-xl text-[var(--text-main)] text-[0.93rem] font-['Outfit'] outline-none transition-all duration-300 placeholder:text-[var(--text-muted)] placeholder:opacity-70`} />
                                    <button type="button" className="absolute right-[11px] bg-none border-none cursor-pointer text-[var(--text-muted)] p-1 flex items-center transition-colors duration-300 hover:text-[var(--primary)]" onClick={() => setShowPassword(p => !p)} aria-label="Toggle password">
                                        {showPassword ? <EyeOff /> : <EyeOpen />}
                                    </button>
                                </div>
                                {errors.password && <span className="text-[0.8rem] text-red-400 pl-0.5">{errors.password}</span>}
                            </div>

                            <div className="flex flex-col gap-2 focus-within:[&>label]:text-[var(--primary)]">
                                <label htmlFor="reg-confirm" className="text-[0.875rem] font-semibold text-[var(--text-muted)] pl-0.5 transition-colors duration-300">Confirm Password</label>
                                <div className="relative flex items-center">
                                    <span className="absolute left-[13px] flex items-center text-[var(--text-muted)] pointer-events-none">
                                        <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none"><path d="M9 12l2 2 4-4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /><rect x="3" y="11" width="18" height="11" rx="2" ry="2" stroke="currentColor" strokeWidth="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>
                                    </span>
                                    <input id="reg-confirm" name="confirm" type={showConfirm ? 'text' : 'password'} placeholder="Re-enter password" value={formData.confirm} onChange={handleChange} autoComplete="new-password" className={`w-full py-[0.72rem] pr-4 pl-[2.6rem] bg-[rgba(255,255,255,0.05)] border-[1.5px] ${errors.confirm ? 'border-red-400 bg-[rgba(248,113,113,0.05)]' : 'border-[var(--glass-border)] focus:border-[var(--primary)] focus:bg-[rgba(99,102,241,0.05)] focus:shadow-[0_0_0_3px_var(--primary-glow)]'} rounded-xl text-[var(--text-main)] text-[0.93rem] font-['Outfit'] outline-none transition-all duration-300 placeholder:text-[var(--text-muted)] placeholder:opacity-70`} />
                                    <button type="button" className="absolute right-[11px] bg-none border-none cursor-pointer text-[var(--text-muted)] p-1 flex items-center transition-colors duration-300 hover:text-[var(--primary)]" onClick={() => setShowConfirm(p => !p)} aria-label="Toggle confirm password">
                                        {showConfirm ? <EyeOff /> : <EyeOpen />}
                                    </button>
                                </div>
                                {errors.confirm && <span className="text-[0.8rem] text-red-400 pl-0.5">{errors.confirm}</span>}
                            </div>

                            <p className="text-[0.8rem] text-[var(--text-muted)] text-center leading-[1.6] -mt-1">
                                By signing up, you agree to our <a href="#" className="color-[var(--primary)] no-underline font-semibold hover:underline">Terms of Service</a> &amp; <a href="#" className="color-[var(--primary)] no-underline font-semibold hover:underline">Privacy Policy</a>.
                            </p>

                            <button type="submit" className="mt-1 py-[0.85rem] px-6 bg-gradient-to-br from-[var(--accent)] to-[var(--primary)] text-white border-none rounded-xl text-base font-bold font-['Outfit'] cursor-pointer flex items-center justify-center gap-2 transition-all duration-250 shadow-[0_4px_20px_rgba(168,85,247,0.35)] tracking-[0.3px] hover:not(:disabled):opacity-90 hover:not(:disabled):-translate-y-0.5 hover:not(:disabled):shadow-[0_8px_28px_rgba(168,85,247,0.45)] disabled:opacity-70 disabled:cursor-not-allowed group" disabled={loading}>
                                {loading ? <span className="w-[22px] h-[22px] border-4 border-white/30 border-t-white rounded-full animate-spin"></span> : <>Create Account <span className="inline-block transition-transform duration-300 group-hover:translate-x-1">→</span></>}
                            </button>

                            <div className="relative text-center my-1 before:content-[''] before:absolute before:top-1/2 before:left-0 before:right-0 before:h-px before:bg-[var(--glass-border)]">
                                <span className="relative bg-[var(--glass-bg)] px-3.5 text-[0.8rem] text-[var(--text-muted)]">or sign up with</span>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-sm:grid-cols-1">
                                <button type="button" className="flex items-center justify-center gap-2 py-[0.65rem] px-4 bg-[rgba(255,255,255,0.05)] border-[1.5px] border-[var(--glass-border)] rounded-xl text-[var(--text-main)] text-[0.88rem] font-semibold font-['Outfit'] cursor-pointer transition-all duration-250 hover:bg-[rgba(168,85,247,0.1)] hover:border-[var(--accent)] hover:-translate-y-0.5">
                                    <svg viewBox="0 0 24 24" width="20" height="20"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" /><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" /><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" /><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" /></svg>
                                    Google
                                </button>
                                <button type="button" className="flex items-center justify-center gap-2 py-[0.65rem] px-4 bg-[rgba(255,255,255,0.05)] border-[1.5px] border-[var(--glass-border)] rounded-xl text-[var(--text-main)] text-[0.88rem] font-semibold font-['Outfit'] cursor-pointer transition-all duration-250 hover:bg-[rgba(168,85,247,0.1)] hover:border-[var(--accent)] hover:-translate-y-0.5">
                                    <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor"><path d="M12 0C5.37 0 0 5.37 0 12c0 5.31 3.435 9.795 8.205 11.385.6.105.825-.255.825-.57 0-.285-.015-1.23-.015-2.235-3.015.555-3.795-.735-4.035-1.41-.135-.345-.72-1.41-1.23-1.695-.42-.225-1.02-.78-.015-.795.945-.015 1.62.87 1.845 1.23 1.08 1.815 2.805 1.305 3.495.99.105-.78.42-1.305.765-1.605-2.67-.3-5.46-1.335-5.46-5.925 0-1.305.465-2.385 1.23-3.225-.12-.3-.54-1.53.12-3.18 0 0 1.005-.315 3.3 1.23.96-.27 1.98-.405 3-.405s2.04.135 3 .405c2.295-1.56 3.3-1.23 3.3-1.23.66 1.65.24 2.88.12 3.18.765.84 1.23 1.905 1.23 3.225 0 4.605-2.805 5.625-5.475 5.925.435.375.81 1.095.81 2.22 0 1.605-.015 2.895-.015 3.3 0 .315.225.69.825.57A12.02 12.02 0 0 0 24 12c0-6.63-5.37-12-12-12z" /></svg>
                                    GitHub
                                </button>
                            </div>
                        </form>

                        <p className="text-center text-[var(--text-muted)] text-[0.9rem] mt-[1.1rem]">
                            Already have an account? <Link to="/login" className="text-[var(--primary)] font-bold no-underline transition-opacity duration-300 hover:opacity-75 hover:underline">Sign in</Link>
                        </p>
                    </div>
                </main>
            </div>
        </>
    )
}

export default Register
